// Prebuild script: reads public/ files and writes them as base64 strings into
// public-bundle.js so pkg compiles them as JS code (no asset system needed).
const fs = require('fs');
const path = require('path');

const files = {
  'index.html': 'text/html; charset=utf-8',
  'app.js':     'application/javascript',
  'style.css':  'text/css',
};

const out = {};
for (const file of Object.keys(files)) {
  out[file] = {
    mime: files[file],
    data: fs.readFileSync(path.join(__dirname, 'public', file), 'base64'),
  };
}

// Embed settings.json so the packaged exe can seed it on first run
try {
  out['settings.json'] = {
    mime: 'application/json',
    data: fs.readFileSync(path.join(__dirname, 'data', 'settings.json'), 'base64'),
  };
} catch (e) {
  console.log('No data/settings.json found, skipping');
}

fs.writeFileSync(
  path.join(__dirname, 'public-bundle.js'),
  `// Auto-generated by bundle-public.js — do not edit manually\nmodule.exports = ${JSON.stringify(out)};\n`
);

console.log('public-bundle.js written');
